//! Real parsing benchmarks for adze
//!
//! This benchmark measures actual parsing performance using valid arithmetic
//! expression fixtures and the adze GLR parser.
//!
//! ## Current Approach (v0.8.0)
//!
//! We use the **arithmetic grammar** with **valid arithmetic expression fixtures**
//! to measure true parsing performance. These fixtures are generated by
//! `cargo xtask generate-fixtures` and contain valid expressions that the grammar
//! can parse without error recovery.
//!
//! ## Why Valid Fixtures Matter
//!
//! - ✅ Measures actual parsing, not error recovery
//! - ✅ Exercises GLR fork/merge logic on valid input
//! - ✅ Provides realistic tree construction costs
//! - ✅ Benchmarks scale with input size (LOC)
//!
//! ## Fixture Sizes
//!
//! - Small: ~100 LOC, ~88 expressions
//! - Medium: ~2,000 LOC, ~1,914 expressions
//! - Large: ~10,000 LOC, ~9,606 expressions
//!
//! ## Regenerating Fixtures
//!
//! ```bash
//! cargo xtask generate-fixtures --force
//! cargo xtask validate-fixtures
//! ```
//!
//! ## Migration Path to Language Grammars
//!
//! When adze-python/javascript are ready:
//! 1. Add language-specific fixture generation
//! 2. Create parallel benchmark groups for each grammar
//! 3. Compare performance against tree-sitter baselines
//!
//! Related:
//! - Spec: docs/specs/REAL_PARSING_BENCHMARKS_SPEC.md
//! - Fixtures: benchmarks/fixtures/arithmetic/

use adze_example::arithmetic::grammar::parse;
use criterion::{BenchmarkId, Criterion, criterion_group, criterion_main};
use std::hint::black_box;

// Load arithmetic fixtures at compile time (deterministic, zero I/O overhead)
const ARITH_SMALL: &str = include_str!("../fixtures/arithmetic/small.expr");
const ARITH_MEDIUM: &str = include_str!("../fixtures/arithmetic/medium.expr");
const ARITH_LARGE: &str = include_str!("../fixtures/arithmetic/large.expr");

/// Benchmark real parsing with arithmetic grammar on valid fixtures
///
/// This benchmarks actual `Parser::parse()` calls on valid arithmetic expressions.
/// Parse times should scale with input size (LOC) in the µs-ms range.
///
/// ## Expected Performance Characteristics
///
/// - Small (~100 LOC): 10-100 µs
/// - Medium (~2k LOC): 200 µs - 2 ms
/// - Large (~10k LOC): 1-10 ms
///
/// Times depend on grammar complexity, GLR conflicts, and tree construction.
fn benchmark_real_parsing(c: &mut Criterion) {
    let mut group = c.benchmark_group("arithmetic_parsing");

    // Pre-validate all fixtures parse successfully
    // This ensures benchmarks measure parsing, not error handling
    for (label, source) in &[
        ("small", ARITH_SMALL),
        ("medium", ARITH_MEDIUM),
        ("large", ARITH_LARGE),
    ] {
        let result = parse(source);
        assert!(
            result.is_ok(),
            "Fixture {} failed to parse! Run: cargo xtask validate-fixtures\nError: {:?}",
            label,
            result.err()
        );
    }

    // Benchmark valid arithmetic expression parsing
    for (label, source) in &[
        ("small", ARITH_SMALL),
        ("medium", ARITH_MEDIUM),
        ("large", ARITH_LARGE),
    ] {
        group.bench_with_input(BenchmarkId::new("parse", label), source, |b, &source| {
            b.iter(|| {
                // REAL PARSING: Actual GLR parser over valid expressions
                // Measures: lexing, parsing, tree construction
                // Does NOT measure: error recovery (inputs are valid)
                let result = parse(source);

                // Force evaluation and unwrap (we know it succeeds from validation)
                black_box(result.unwrap())
            });
        });
    }

    group.finish();
}

/// Benchmark fixture loading overhead (should be ~0ns with include_str!)
///
/// This validates that compile-time embedding works correctly.
/// With `include_str!()`, this should be just a pointer dereference.
fn benchmark_fixture_loading(c: &mut Criterion) {
    c.bench_function("fixture_loading_small", |b| {
        b.iter(|| {
            // With include_str!(), this is just a pointer dereference
            // Expected time: < 1 ns
            let source = ARITH_SMALL;
            black_box(source)
        });
    });

    c.bench_function("fixture_loading_large", |b| {
        b.iter(|| {
            let source = ARITH_LARGE;
            black_box(source)
        });
    });
}

/// Benchmark parse result validation (tree traversal overhead)
///
/// Measures cost of validating parse trees, which will be important
/// for correctness testing alongside performance benchmarks.
fn benchmark_parse_validation(c: &mut Criterion) {
    // Pre-parse once to get a tree for validation benchmarks
    let small_result = parse(ARITH_SMALL);

    c.bench_function("validate_parse_result", |b| {
        b.iter(|| {
            // Simulate validation: check if parse succeeded and extract result
            let is_valid = small_result.is_ok();
            black_box(is_valid)
        });
    });
}

criterion_group!(
    benches,
    benchmark_real_parsing,
    benchmark_fixture_loading,
    benchmark_parse_validation
);
criterion_main!(benches);
